mapper.select:
select 
from tech_briefing_subscription
where channel_type = #{channelType}
  and webhook_url = #{webhookUrl}
  and status = 'ENABLED'
limit 1

mapper.insert:
insert into tech_briefing_subscription (
    user_id, channel_type, webhook_url, webhook_secret, target_name, config_hash, topic_preferences,
    frequency, status, source, last_push_at, last_test_at, last_push_status
) values (
    #{userId}, #{channelType}, #{webhookUrl}, #{webhookSecret}, #{targetName}, #{configHash}, #{topicPreferences},
    #{frequency}, #{status}, #{source}, #{lastPushAt}, #{lastTestAt}, #{lastPushStatus}
)

mapper.update:
update tech_briefing_subscription
set status = #{status}
where id = #{id}

update tech_briefing_subscription
set last_test_at = #{lastTestAt},
    last_push_status = #{lastPushStatus}
where id = #{id}
